code = """import json

# Get the file path from stored results
file_path = locals()['var_functions.query_db:32']

# Open and load the JSON file
with open(file_path) as f:
    articles = json.load(f)

print('Total articles loaded:', len(articles))

# Define sports keywords
sports_keywords = ['sports','football','soccer','basketball','baseball','tennis','golf','race','racing','olympic','game','team','player','coach','match','athlete','championship','tournament']

# Find sports articles and track the longest description
sports_articles = []
longest_sports_title = ''
longest_sports_length = 0

for article in articles:
    title_lower = article['title'].lower()
    desc_lower = article['description'].lower()
    
    # Check if this is a sports article
    is_sports = False
    for keyword in sports_keywords:
        if keyword in title_lower or keyword in desc_lower:
            is_sports = True
            break
    
    if is_sports:
        desc_len = len(article['description'])
        sports_articles.append({
            'title': article['title'],
            'length': desc_len
        })
        
        # Track the longest
        if desc_len > longest_sports_length:
            longest_sports_length = desc_len
            longest_sports_title = article['title']

print('Sports articles found:', len(sports_articles))
print('Longest sports article title:', longest_sports_title)
print('Description length:', longest_sports_length)

result = longest_sports_title if longest_sports_title else 'No sports articles found'

print('__RESULT__:')
print(json.dumps(result))"""

